package org.apache.kafka.streams.state.internals;

import org.apache.kafka.common.utils.Bytes;
import org.apache.kafka.streams.query.Position;

import java.lang.reflect.Field;
import java.nio.charset.StandardCharsets;

/**
 * Fray test to verify that MemoryLRUCache does not have a cyclic lock
 * dependency between its intrinsic monitor ({@code this}) and the
 * {@code position} field.
 *
 * <p>Before the fix, the restore callback in {@code init()} acquired
 * {@code position} then called {@code put()} which acquired {@code this},
 * while normal {@code put()}/{@code delete()} acquired {@code this} then
 * {@code position} — a classic AB/BA deadlock.
 *
 * <p>Run via: {@code fray-gradle org.apache.kafka.streams.state.internals.MemoryLRUCacheDeadlockTest -- --iter 1000}
 */
public class MemoryLRUCacheDeadlockTest {

    public static void main(final String[] args) throws Exception {
        final MemoryLRUCache cache = new MemoryLRUCache("test-store", 100);

        // Extract the position field so we can simulate the restore-callback
        // lock ordering (position -> this) that existed before the fix.
        final Field positionField = MemoryLRUCache.class.getDeclaredField("position");
        positionField.setAccessible(true);
        final Position position = (Position) positionField.get(cache);

        // Thread 1: normal put() path — acquires this, then position
        final Thread writer = new Thread(() -> {
            for (int i = 0; i < 5; i++) {
                final byte[] key = ("k" + i).getBytes(StandardCharsets.UTF_8);
                final byte[] val = ("v" + i).getBytes(StandardCharsets.UTF_8);
                cache.put(Bytes.wrap(key), val);
            }
        });

        // Thread 2: simulates the OLD restore path — acquires position, then
        // calls put() which acquires this.  With the fix applied, the real
        // restore callback no longer wraps put() inside synchronized(position),
        // so this ordering is the one that USED to deadlock.
        final Thread restorer = new Thread(() -> {
            for (int i = 0; i < 5; i++) {
                synchronized (position) {
                    final byte[] key = ("r" + i).getBytes(StandardCharsets.UTF_8);
                    final byte[] val = ("rv" + i).getBytes(StandardCharsets.UTF_8);
                    cache.put(Bytes.wrap(key), val);
                }
            }
        });

        writer.start();
        restorer.start();
        writer.join();
        restorer.join();
    }
}

