        final Field positionField = MemoryLRUCache.class.getDeclaredField("position");
        positionField.setAccessible(true);
        final Position position = (Position) positionField.get(cache);

        // Thread 1: normal put()/delete() path — acquires this, then position
        final Thread writer = new Thread(() -> {
            for (int i = 0; i < 5; i++) {
                final byte[] key = ("k" + i).getBytes(StandardCharsets.UTF_8);
                final byte[] val = ("v" + i).getBytes(StandardCharsets.UTF_8);
