        // first (which acquires this -> position), then separately acquires
        // position for the changelog position update.
        final Thread restorer = new Thread(() -> {
            for (int i = 0; i < 5; i++) {
                final byte[] key = ("r" + i).getBytes(StandardCharsets.UTF_8);
                final byte[] val = ("rv" + i).getBytes(StandardCharsets.UTF_8);
                // Fixed path: put() first, then position lock separately
                cache.put(Bytes.wrap(key), val);
                synchronized (position) {
